SELECT oi.orderItemNo, oi.orderNo, oi.prodVariantId, oi.prodNo AS prodNo, oi.productName AS prodName, oi.optionText, p.thumb1FileId, oi.sellerUid, s.companyName AS sellerName, oi.count, oi.originalPrice AS originalPrice, oi.discountRate AS discountRate, GREATEST((oi.originalPrice * oi.count) - oi.total, 0) AS discountAmount, oi.price, oi.total, oi.shippingFee, oi.itemStatus, sh.shipmentNo, sh.courierName, sh.trackingNo, sh.status AS shipmentStatus, o.createdAt FROM order_item oi JOIN `order` o ON o.orderNo = oi.orderNo LEFT JOIN product p ON p.prodNo = oi.prodNo LEFT JOIN seller s ON s.uid = oi.sellerUid LEFT JOIN shipment_item si ON si.orderItemNo = oi.orderItemNo LEFT JOIN shipment sh ON sh.shipmentNo = si.shipmentNo WHERE oi.orderNo = #{orderNo}
AND oi.sellerUid = #{sellerUid}
ORDER BY oi.orderItemNo ASC

SELECT oi.orderItemNo, oi.orderNo, oi.prodVariantId, oi.prodNo AS prodNo, oi.productName AS prodName, oi.optionText, p.thumb1FileId, oi.sellerUid, s.companyName AS sellerName, oi.count, oi.originalPrice AS originalPrice, oi.discountRate AS discountRate, GREATEST((oi.originalPrice * oi.count) - oi.total, 0) AS discountAmount, oi.price, oi.total, oi.shippingFee, oi.itemStatus, sh.shipmentNo, sh.courierName, sh.trackingNo, sh.status AS shipmentStatus, o.createdAt FROM order_item oi JOIN `order` o ON o.orderNo = oi.orderNo LEFT JOIN product p ON p.prodNo = oi.prodNo LEFT JOIN seller s ON s.uid = oi.sellerUid LEFT JOIN shipment_item si ON si.orderItemNo = oi.orderItemNo LEFT JOIN shipment sh ON sh.shipmentNo = si.shipmentNo WHERE oi.orderNo = #{orderNo} AND si.shipmentItemNo IS NULL AND oi.itemStatus = 'PAID'
AND oi.sellerUid = #{sellerUid}
ORDER BY oi.sellerUid ASC, oi.orderItemNo ASC

SELECT oi.orderItemNo, oi.orderNo, oi.prodVariantId, oi.prodNo AS prodNo, oi.productName AS prodName, oi.optionText, p.thumb1FileId, oi.sellerUid, s.companyName AS sellerName, oi.count, oi.originalPrice AS originalPrice, oi.discountRate AS discountRate, GREATEST((oi.originalPrice * oi.count) - oi.total, 0) AS discountAmount, oi.price, oi.total, oi.shippingFee, oi.itemStatus, sh.shipmentNo, sh.courierName, sh.trackingNo, sh.status AS shipmentStatus, o.createdAt FROM order_item oi JOIN `order` o ON o.orderNo = oi.orderNo LEFT JOIN product p ON p.prodNo = oi.prodNo LEFT JOIN seller s ON s.uid = oi.sellerUid LEFT JOIN shipment_item si ON si.orderItemNo = oi.orderItemNo LEFT JOIN shipment sh ON sh.shipmentNo = si.shipmentNo WHERE oi.orderItemNo IN
#{orderItemNo}
AND oi.sellerUid = #{sellerUid}
ORDER BY oi.orderItemNo ASC

